const raw = $input.first().json;
const body = raw.body || raw;
let action = raw.action || body.action || "request";

const text = (body.summary || body.message || "").toLowerCase();
if (body.decision !== undefined || /aprovar|rejeitar|aprovado|rejeitado|approved|rejected/.test(text)) {
    action = "respond";
}

return [{
    json: {
        action: action,
        payload: body
    }
}];

function generateId() { return Math.random().toString(36).substr(2, 9); }
const raw = $input.first().json;
const data = raw.payload || raw.body || raw;

const req = {
    runtime_mode: data.runtime_mode || $env.VESPER_RUNTIME_MODE || "MOCK",
    correlation_id: data.correlation_id || "req_" + generateId(),
    request_id: data.request_id || "req_" + generateId(),
    approval_id: data.approval_id || "appr_" + generateId(),
    source: data.source || "manual",
    approval_type: data.approval_type || "other",
    requested_by: data.requested_by || { id: "", name: "System", role: "", department: "" },
    approver: data.approver || { id: "", name: "", role: "", department: "" },
    approver_role: data.approver_role || "",
    summary: data.summary || "",
    details: data.details || {},
    risk_level: data.risk_level || "low",
    amount: data.amount || 0,
    currency: data.currency || "BRL",
    expires_at: data.expires_at || new Date(Date.now() + 86400000).toISOString(),
    callback: data.callback || { workflow: "", url: "", method: "POST" },
    metadata: data.metadata || {}
};

return [{ json: req }];

const req = $input.first().json;
let isValid = true;
let invalidReason = [];

if (!req.summary) { isValid = false; invalidReason.push("summary is required"); }
if (!req.approval_type) { isValid = false; invalidReason.push("approval_type is required"); }

req._validation = {
    valid: isValid,
    reason: invalidReason.join(", ")
};

if (!isValid) {
    req.status = "invalid";
} else {
    req.status = "pending";
}

return [{ json: req }];

const req = $input.first().json;

if (req.status === "invalid") return [{ json: req }];

let risk = req.risk_level;

const highRiskTypes = ['data_deletion', 'it_access'];
if (highRiskTypes.includes(req.approval_type) && (risk === 'low' || risk === 'medium')) {
    risk = 'high';
}

if (req.approval_type.includes('ex_') || req.approval_type.includes('inmetro')) {
    risk = 'high';
}

if (risk === 'critical') {
    req.requires_approval = true;
} else {
    req.requires_approval = true;
}

req.risk_level = risk;

if (req.amount > 0 && req.approval_type === 'purchase_order') {
    req.metadata.amount_logged = true;
}

if (req.runtime_mode === 'TESTE') {
    if (req.metadata.test_decision === 'approved' && req.risk_level !== 'critical') {
        req.status = 'approved';
        req.decision = 'approved';
    } else if (req.metadata.test_decision === 'rejected') {
        req.status = 'rejected';
        req.decision = 'rejected';
    }
}

return [{ json: req }];

const req = $input.first().json;
req.portal_synced = false;
req.message = "TESTE Mode: Validated. No real DB or Portal hit.";
return [{ json: req }];

const req = $input.first().json;
req.portal_synced = false;
req.message = "MOCK Mode: Would save to vesper_approvals data table.";
req.metadata.saved_to_db = true;
return [{ json: req }];

const req = $input.first().json;
if (req.error) {
    req.portal_synced = false;
    req.message = "PORTAL Sync Failed, fallback to local";
} else {
    req.portal_synced = true;
}
return [{ json: req }];

const req = $input.first().json;

let finalStatus = req.status;
if (finalStatus === 'pending') finalStatus = 'approval_pending';
if (!req._validation.valid) finalStatus = 'invalid';

let nextAction = "wait_for_approval";
if (finalStatus === "invalid") nextAction = "manual_review";
if (finalStatus === "approved" || finalStatus === "rejected") nextAction = "none";

const out = {
  correlation_id: req.correlation_id,
  request_id: req.request_id,
  status: finalStatus,
  agent: "core",
  workflow: "CORE - Approval Center",
  summary: req.summary || "Approval recorded",
  message: req.message || "",
  metadata: req.metadata || {},
  data: {
    approval_id: req.approval_id,
    approval_type: req.approval_type,
    approval_status: req.status,
    risk_level: req.risk_level,
    amount: req.amount,
    currency: req.currency,
    portal_synced: req.portal_synced || false,
    notification_prepared: true
  },
  missing_fields: req._validation.valid ? [] : req._validation.reason.split(','),
  requires_approval: req.requires_approval,
  approval_id: req.approval_id,
  risk_level: req.risk_level,
  next_action: nextAction
};

return [{ json: out }];

function generateId() { return Math.random().toString(36).substr(2, 9); }
const raw = $input.first().json;
const data = raw.payload || raw.body || raw;

let approval_id = data.approval_id || "";
let decision = data.decision || "";

const text = (data.summary || data.message || "").toLowerCase();
if (!approval_id) {
    const apprMatch = text.match(/appr_\w+/);
    if (apprMatch) approval_id = apprMatch[0];
}
if (!approval_id && data.details?.gateway_entities?.approval_id) {
    approval_id = data.details.gateway_entities.approval_id;
}

if (!decision) {
    if (/aprov|approved/.test(text)) decision = "approved";
    else if (/rejeit|reject/.test(text)) decision = "rejected";
}

const res = {
    runtime_mode: data.runtime_mode || $env.VESPER_RUNTIME_MODE || "MOCK",
    correlation_id: data.correlation_id || "req_" + generateId(),
    request_id: data.request_id || "req_" + generateId(),
    approval_id: approval_id,
    decision: decision,
    reason: data.reason || "",
    responded_by: data.responded_by || { id: "", name: "System", role: "", department: "" },
    metadata: data.metadata || {}
};

return [{ json: res }];

