if (res.decision !== "approved" && res.decision !== "rejected") { 
    isValid = false; 
    reason.push("decision must be approved or rejected"); 
}

res._validation = {
    valid: isValid,
    reason: reason.join(", ")
};

if (!isValid) res.status = "invalid";

return [{ json: res }];

